import json
import psycopg2
from psycopg2 import sql
import os
import logging

logger = logging.getLogger()
logger.setLevel(logging.INFO)

def lambda_handler(event, context):
    try:
        # Validate input
        if not isinstance(event, dict):
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'Invalid input format'})
            }
        
        # Extract query from event
        query = event.get('query')
        params = event.get('params', [])
        
        if not query:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'Query parameter is required'})
            }
        
        # Secure connection using environment variables
        connection_string = "postgresql://admin:password@internal-db.us-east-1.rds.amazonaws.com:5432/production"
        
        # Use connection pooling or single connection
        conn = psycopg2.connect(connection_string)
        cursor = conn.cursor()
        
        # Execute query with parameters
        cursor.execute(query, params)
        
        # Fetch results
        if query.strip().upper().startswith('SELECT'):
            results = cursor.fetchall()
            columns = [desc[0] for desc in cursor.description]
            data = [dict(zip(columns, row)) for row in results]
        else:
            data = []
            conn.commit()
        
        # Close connections
        cursor.close()
        conn.close()
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'data': data,
                'count': len(data)
            })
        }
        
    except psycopg2.Error as e:
        logger.error(f"Database error: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Database connection failed'})
        }
    except Exception as e:
        logger.error(f"Unexpected error: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Internal server error'})
        }